import React from 'react';
import { Navigate } from 'react-router-dom';

// This component is for routes that an authenticated user should NOT see, like login/register.
// If the user is authenticated, it redirects them to the main page.
function PublicRoute({ children })
{
    const isAuthenticated = !!localStorage.getItem('auth_token');

    // If authenticated, redirect to the main dashboard page.
    // If not, render the children (e.g., the Login or Register page).
    return isAuthenticated ? <Navigate to="/" replace /> : children;
}

export default PublicRoute;
